import { useCart } from '../CartContext';

function Cart() {
  const { cart, fetchCart } = useCart();

  if (cart.length === 0) {
    return (
      <div className="cart-page">
        <h1>Your Cart</h1>
        <p>Your cart is empty.</p>
      </div>
    );
  }

  return (
    <div className="cart-page">
      <h1>Your Cart</h1>
      {/* cart items go here */}
    </div>
  );
}

export default Cart;
